import React, { useState, useEffect } from 'react';
import Table from 'react-bootstrap/Table';

function App() {
  const [data, setData] = useState([]);
  useEffect(() => {
    fetch('https://raw.githubusercontent.com/mozilla-platform-ops/bean-counter/main/data/count-day-2021-10.json')
      .then((r) => r.json())
      .then(setData)
      .catch(console.error)
  }, []);
  return (
    <div className="App">
      <Table striped bordered hover>
        <thead>
          <tr>
            <th></th>
            {
              [...new Set(data.map(x => x.period))].map((period) => (
                <th key={period}>{period}</th>
              ))
            }
          </tr>
        </thead>
        <tbody>
          {
            [...new Set(data.map(x => x.queue))].map((queue, qI) => (
              <tr key={queue}>
                <th>{queue}</th>
                {
                  [...new Set(data.map(x => x.period))].map((period, pI) => (
                    <td key={"${qI}-${pI}"}>{(data.find((x) => x.queue === queue && x.period === period) || { tasks: 0 }).tasks}</td>
                  ))
                }
              </tr>
            ))
          }
        </tbody>
      </Table>
    </div>
  );
}

export default App;
